      this._components.set('badge', 'display:inline-flex;align-items:center;padding:0.25rem 0.5rem;border-radius:9999px;font-size:0.75rem;font-weight:500');
      this._components.set('alert', 'padding:1rem;border-radius:0.375rem;margin-bottom:1rem');
